/**
 * Project Templates Registry
 * Provides predefined project templates for scaffolding
 */

import staticWebsiteTemplate from './static-website.js';
import reactAppTemplate from './react-app.js';
import expressApiTemplate from './express-api.js';
import fullStackTemplate from './full-stack.js';
import vueAppTemplate from './vue-app.js';
import nextAppTemplate from './next-app.js';
import flaskApiTemplate from './flask-api.js';
import fastapiApiTemplate from './fastapi-api.js';
import djangoAppTemplate from './django-app.js';

const templates = {
  'static-website': staticWebsiteTemplate,
  'react-app': reactAppTemplate,
  'express-api': expressApiTemplate,
  'full-stack': fullStackTemplate,
  'vue-app': vueAppTemplate,
  'next-app': nextAppTemplate,
  'flask-api': flaskApiTemplate,
  'fastapi-api': fastapiApiTemplate,
  'django-app': djangoAppTemplate
};

/**
 * Get available template names
 * @returns {string[]} Array of template names
 */
export function getTemplateNames() {
  return Object.keys(templates);
}

/**
 * Get template by name
 * @param {string} templateName - Name of the template
 * @returns {object|null} Template object or null if not found
 */
export function getTemplate(templateName) {
  return templates[templateName] || null;
}

/**
 * Generate files for a template
 * @param {string} templateName - Name of the template
 * @param {string} projectName - Name of the project
 * @param {object} options - Additional options
 * @returns {object[]} Array of file objects {path, content}
 */
export function generateTemplate(templateName, projectName, options = {}) {
  const template = getTemplate(templateName);
  if (!template) {
    throw new Error(`Template "${templateName}" not found`);
  }

  return template.generate(projectName, options);
}

export { templates };
export default {
  getTemplateNames,
  getTemplate,
  generateTemplate,
  templates
};